                      </td>
                      <td>
                        <span className={`badge ${assignment.status === "active" ? "badge-green" : assignment.status === "closed" ? "badge-gray" : "badge-red"}`}>
                          {assignment.status === "active" ? "Đang mở" : assignment.status === "closed" ? "Đã đóng" : "Ẩn"}
